import { useState, useEffect } from "react";
import { RadialBarChart, RadialBar, PolarAngleAxis } from "recharts";

const API = "http://127.0.0.1:8000";

const getCategoryColor = (category) => {
  const colors = {
    "Severely Underweight": "#818cf8",
    "Underweight": "#60a5fa",
    "Healthy": "#4ade80",
    "Overweight": "#facc15",
    "Obese": "#fb923c",
    "Severely Obese": "#f87171",
  };
  return colors[category] || "#4ade80";
};

const mealLabels = {
  breakfast: "🌅 Breakfast",
  morning_snack: "🍎 Morning Snack",
  lunch: "🍱 Lunch",
  evening_snack: "☕ Evening Snack",
  dinner: "🌙 Dinner",
};

export default function Dashboard({ token, onLogout, onNewPlan }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("overview");

  useEffect(() => {
    fetchDashboard();
  }, []);

  const fetchDashboard = async () => {
    try {
      const res = await fetch(`${API}/dashboard`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const json = await res.json();
      setData(json);
    } catch {
      setData({ has_plan: false });
    }
    setLoading(false);
  };

  if (loading) return (
    <div style={s.loadingPage}>
      <p style={s.loadingText}>Loading your dashboard...</p>
    </div>
  );

  if (!data?.has_plan) return (
    <div style={s.loadingPage}>
      <div style={s.emptyCard}>
        <p style={{ fontSize: "48px" }}>🥗</p>
        <h2 style={{ color: "#fff", marginTop: "16px" }}>No Plan Yet</h2>
        <p style={{ color: "#555", marginTop: "8px" }}>Complete the BMI calculator to generate your plan</p>
        <button style={s.startBtn} onClick={onNewPlan}>Start Now →</button>
      </div>
    </div>
  );

  const bmiData = [{ value: Math.min((data.bmi / 40) * 100, 100) }];

  const tabs = ["overview", "diet", "supplements"];

  return (
    <div style={s.layout}>

      {/* Sidebar */}
      <div style={s.sidebar}>
        <div style={s.logo}>🧬 <span style={{ color: "#4ade80" }}>Dietify</span></div>

        <nav style={s.nav}>
          {[
            { id: "overview", icon: "📊", label: "Overview" },
            { id: "diet", icon: "🥗", label: "Diet Plan" },
            { id: "supplements", icon: "💊", label: "Supplements" },
          ].map(item => (
            <button key={item.id} style={{
              ...s.navItem,
              background: activeTab === item.id ? "#1a1a1a" : "transparent",
              color: activeTab === item.id ? "#4ade80" : "#555",
              borderLeft: activeTab === item.id ? "3px solid #4ade80" : "3px solid transparent",
            }} onClick={() => setActiveTab(item.id)}>
              <span>{item.icon}</span>
              <span>{item.label}</span>
            </button>
          ))}
        </nav>

        <div style={s.sidebarBottom}>
          <button style={s.newPlanBtn} onClick={onNewPlan}>🔄 New Plan</button>
          <button style={s.logoutBtn} onClick={onLogout}>← Logout</button>
        </div>
      </div>

      {/* Main Content */}
      <div style={s.main}>

        {/* Top Bar */}
        <div style={s.topBar}>
          <div>
            <h1 style={s.pageTitle}>
              {activeTab === "overview" && "Health Overview"}
              {activeTab === "diet" && "Diet Plan"}
              {activeTab === "supplements" && "Supplements"}
            </h1>
            <p style={s.pageSubtitle}>Last updated: {data.date_created}</p>
          </div>
          <div style={s.userInfo}>
            <div style={s.avatar}>{data.user_name?.[0]?.toUpperCase()}</div>
            <div>
              <p style={s.userName}>{data.user_name}</p>
              <p style={s.userEmail}>{data.user_email}</p>
            </div>
          </div>
        </div>

        {/* OVERVIEW TAB */}
        {activeTab === "overview" && (
          <div style={s.content}>

            {/* Top Stats */}
            <div style={s.statsGrid}>
              {[
                { label: "Current Weight", value: `${data.weight} kg`, icon: "⚖️", color: "#60a5fa" },
                { label: "Target Weight", value: `${data.target_weight} kg`, icon: "🎯", color: "#4ade80" },
                { label: "Daily Calories", value: `${data.daily_calories} kcal`, icon: "🔥", color: "#fb923c" },
                { label: "Timeline", value: `${data.timeline_weeks} weeks`, icon: "📅", color: "#a78bfa" },
              ].map((stat, i) => (
                <div key={i} style={s.statCard}>
                  <div style={s.statIcon}>{stat.icon}</div>
                  <p style={s.statVal}>{stat.value}</p>
                  <p style={s.statLbl}>{stat.label}</p>
                </div>
              ))}
            </div>

            {/* BMI + Info Row */}
            <div style={s.midRow}>

              {/* BMI Gauge */}
              <div style={s.bmiCard}>
                <p style={s.cardTitle}>Body Mass Index</p>
                <div style={{ position: "relative", display: "flex", justifyContent: "center" }}>
                  <RadialBarChart
                    width={200} height={120}
                    cx={100} cy={110}
                    innerRadius={70} outerRadius={100}
                    startAngle={180} endAngle={0}
                    data={bmiData}
                  >
                    <PolarAngleAxis type="number" domain={[0, 100]} angleAxisId={0} tick={false} />
                    <RadialBar
                      background={{ fill: "#222" }}
                      dataKey="value"
                      angleAxisId={0}
                      fill={getCategoryColor(data.bmi_category)}
                      cornerRadius={6}
                    />
                  </RadialBarChart>
                  <div style={s.bmiOverlay}>
                    <p style={s.bmiNum}>{data.bmi}</p>
                    <p style={{ fontSize: "11px", color: "#555" }}>BMI</p>
                  </div>
                </div>
                <p style={{ ...s.bmiCat, color: getCategoryColor(data.bmi_category) }}>
                  {data.bmi_category}
                </p>
                <div style={s.bmiScale}>
                  {["Severely\nUnderweight", "Underweight", "Healthy", "Overweight", "Obese", "Severely\nObese"].map((cat, i) => (
                    <div key={i} style={{
                      ...s.scaleItem,
                      background: ["#818cf8", "#60a5fa", "#4ade80", "#facc15", "#fb923c", "#f87171"][i],
                      opacity: data.bmi_category === cat.replace("\n", " ") ? 1 : 0.3,
                    }} />
                  ))}
                </div>
              </div>

              {/* Goal Info */}
              <div style={s.goalCard}>
                <p style={s.cardTitle}>Your Goal</p>
                <div style={s.goalRows}>
                  <div style={s.goalRow}>
                    <span style={s.goalLabel}>Current BMI</span>
                    <span style={s.goalValue}>{data.bmi}</span>
                  </div>
                  <div style={s.goalRow}>
                    <span style={s.goalLabel}>Target BMI</span>
                    <span style={s.goalValue}>{data.target_bmi}</span>
                  </div>
                  <div style={s.goalRow}>
                    <span style={s.goalLabel}>Weight Change</span>
                    <span style={{ ...s.goalValue, color: data.weight_change > 0 ? "#4ade80" : "#f87171" }}>
                      {data.weight_change > 0 ? "+" : ""}{data.weight_change} kg
                    </span>
                  </div>
                  <div style={s.goalRow}>
                    <span style={s.goalLabel}>Calorie {data.deficit_surplus?.includes("deficit") ? "Deficit" : "Surplus"}</span>
                    <span style={s.goalValue}>{data.deficit_surplus}</span>
                  </div>
                  <div style={s.goalRow}>
                    <span style={s.goalLabel}>Realistic</span>
                    <span style={{ ...s.goalValue, color: data.realistic === "Yes" ? "#4ade80" : "#f87171" }}>
                      {data.realistic === "Yes" ? "✅ Yes" : "⚠️ Challenging"}
                    </span>
                  </div>
                  <div style={s.goalRow}>
                    <span style={s.goalLabel}>Fitness Goal</span>
                    <span style={s.goalValue}>{data.goal?.replace("_", " ")}</span>
                  </div>
                </div>
              </div>

              {/* Body Stats */}
              <div style={s.goalCard}>
                <p style={s.cardTitle}>Body Stats</p>
                <div style={s.goalRows}>
                  {[
                    { label: "Age", value: `${data.age} years` },
                    { label: "Height", value: `${data.height} cm` },
                    { label: "Weight", value: `${data.weight} kg` },
                    { label: "Target Weight", value: `${data.target_weight} kg` },
                    { label: "Timeline", value: `${data.timeline_weeks} weeks` },
                    { label: "Budget", value: data.budget ? `₹${data.budget}/month` : "No supplements" },
                  ].map((item, i) => (
                    <div key={i} style={s.goalRow}>
                      <span style={s.goalLabel}>{item.label}</span>
                      <span style={s.goalValue}>{item.value}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Advice */}
            {data.advice && (
              <div style={s.adviceCard}>
                <p style={s.cardTitle}>💡 AI Advice</p>
                <p style={s.adviceText}>{data.advice}</p>
              </div>
            )}

          </div>
        )}

        {/* DIET TAB */}
        {activeTab === "diet" && (
          <div style={s.content}>
            <div style={s.mealGrid}>
              {data.meals && Object.entries(data.meals).map(([key, meal]) => (
                <div key={key} style={s.mealCard}>
                  <div style={s.mealHeader}>
                    <p style={s.mealType}>{mealLabels[key] || key}</p>
                    <span style={s.calBadge}>{meal.calories} kcal</span>
                  </div>
                  <p style={s.mealName}>{meal.name}</p>
                  <p style={s.mealIngredients}>🥄 {meal.ingredients}</p>
                </div>
              ))}
            </div>
            <div style={s.totalBar}>
              <span style={{ color: "#888" }}>Total Daily Calories</span>
              <span style={{ color: "#4ade80", fontWeight: "bold", fontSize: "18px" }}>{data.total_calories} kcal</span>
            </div>
          </div>
        )}

        {/* SUPPLEMENTS TAB */}
        {activeTab === "supplements" && (
          <div style={s.content}>
            {data.supplements && data.supplements.length > 0 ? (
              <div style={s.suppGrid}>
                {data.supplements.map((supp, i) => (
                  <div key={i} style={s.suppCard}>
                    <p style={s.suppIcon}>💊</p>
                    <p style={s.suppName}>{supp.name}</p>
                    <p style={s.suppBrand}>🏷️ {supp.brand}</p>
                    <div style={s.suppDetails}>
                      <span style={s.costBadge}>{supp.cost}</span>
                      <span style={s.doseBadge}>📏 {supp.dose}</span>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div style={s.emptyCard}>
                <p style={{ fontSize: "48px" }}>💊</p>
                <h2 style={{ color: "#fff", marginTop: "16px" }}>No Supplements</h2>
                <p style={{ color: "#555", marginTop: "8px" }}>You chose not to include supplements in your plan</p>
                <button style={s.startBtn} onClick={onNewPlan}>Create New Plan with Supplements</button>
              </div>
            )}
          </div>
        )}

      </div>
    </div>
  );
}

